describe('unpadMessage', () => {
  it('should correctly extract the original message from a valid padded frame', () => {
    const original = new Uint8Array([10, 20, 30, 40, 50]);
    const padded = padMessage(original);
    const result = unpadMessage(padded);

    expect(result).toBeInstanceOf(Uint8Array);
    expect(result.length).toBe(original.length);
    expect(result).toEqual(original);
  });

  it('should return a new Uint8Array that does not alias the input buffer', () => {
    const original = new Uint8Array([1, 2, 3]);
    const padded = padMessage(original);
    const result = unpadMessage(padded);

    expect(result.buffer).not.toBe(padded.buffer);

    // Mutating result should not affect padded
    result[0] = 0;
    expect(padded[0]).toBe(1);
  });

  it('should work correctly on a 2-byte frame encoding length 0 (empty message)', () => {
    const frame = new Uint8Array([0, 0]);
    const result = unpadMessage(frame);

    expect(result).toBeInstanceOf(Uint8Array);
    expect(result.length).toBe(0);
    expect(result).toEqual(new Uint8Array(0));
  });

  it('should work when decoded length equals paddedBytes.length - 2 (no padding gap)', () => {
    // Create a 6-byte frame: 4 bytes message + 2 bytes length suffix encoding 4
    const frame = new Uint8Array([0xAA, 0xBB, 0xCC, 0xDD, 0x00, 0x04]);
    const result = unpadMessage(frame);

    expect(result.length).toBe(4);
    expect(result).toEqual(new Uint8Array([0xAA, 0xBB, 0xCC, 0xDD]));
  });

  it('should throw RangeError when paddedBytes is empty (length 0)', () => {
    const input = new Uint8Array(0);
    expect(() => unpadMessage(input)).toThrow(RangeError);
  });

  it('should throw RangeError when paddedBytes has only 1 byte', () => {
    const input = new Uint8Array(1);
    expect(() => unpadMessage(input)).toThrow(RangeError);
  });

  it('should throw RangeError when length suffix claims more bytes than available (corrupted_length)', () => {
    // 4-byte frame where last 2 bytes encode length 5 (exceeds 4 - 2 = 2 available bytes)
    const frame = new Uint8Array([0x00, 0x00, 0x00, 0x05]);
    expect(() => unpadMessage(frame)).toThrow(RangeError);
  });

  it('should throw RangeError when length suffix claims exactly 1 more than capacity', () => {
    // 4-byte frame where last 2 bytes encode length 3 (exceeds 4 - 2 = 2 available bytes)
    const frame = new Uint8Array([0x00, 0x00, 0x00, 0x03]);
    expect(() => unpadMessage(frame)).toThrow(RangeError);
  });

  it('should throw RangeError for a large claimed length in a small frame', () => {
    // 2-byte frame where last 2 bytes encode length 1 (exceeds 2 - 2 = 0 available bytes)
    const frame = new Uint8Array([0x00, 0x01]);
    expect(() => unpadMessage(frame)).toThrow(RangeError);
  });

  it('should detect tampered length suffix on a valid padded frame', () => {
    const original = new Uint8Array([10, 20, 30, 40, 50]);
    const padded = padMessage(original);

    // Tamper: set length suffix to claim a much larger message
    // This should either throw or return incorrect data
    const tampered = new Uint8Array(padded);
    // Encode length as 2000 (big-endian): 0x07D0
    tampered[tampered.length - 2] = 0x07;
    tampered[tampered.length - 1] = 0xD0;

    // The claimed length 2000 <= frame_size - 2, so it might not throw,
    // but the extracted data should NOT match the original
    let resultMatchesOriginal = false;
    try {
      const result = unpadMessage(tampered);
      resultMatchesOriginal = (result.length === original.length) &&
        result.every((byte, i) => byte === original[i]);
    } catch (e) {
      // If it throws, that's also acceptable — the tamper is detected
      resultMatchesOriginal = false;
    }
    expect(resultMatchesOriginal).toBe(false);
  });

  it('should throw RangeError when length suffix exceeds frame capacity by a large margin', () => {
    // 10-byte frame where last 2 bytes encode length 255 (far exceeds 10 - 2 = 8)
    const frame = new Uint8Array(10);
    frame[8] = 0x00;
    frame[9] = 0xFF; // length = 255
    expect(() => unpadMessage(frame)).toThrow(RangeError);
  });

  it('should correctly extract message with big-endian uint16 length for multi-byte length values', () => {
    // Test with a message length that needs both bytes of the uint16
    const msgLength = 300; // 0x012C in big-endian
    const original = new Uint8Array(msgLength);
    crypto.getRandomValues(original);

    const padded = padMessage(original);
    const result = unpadMessage(padded);

    expect(result.length).toBe(msgLength);
    expect(result).toEqual(original);

    // Verify the length encoding directly
    const highByte = padded[padded.length - 2];
    const lowByte = padded[padded.length - 1];
    expect((highByte << 8) | lowByte).toBe(300);
  });
});
